parameters.jsCode:
const root = $json.body || $json;
const isRealWorkable = root.event_type === 'candidate_moved' && root.data;

const targetSlug = isRealWorkable
  ? (root.data?.stage_kind || '')
  : (root.target_stage?.slug || '');
if (targetSlug !== 'interview') return [];

const sourceSlug = isRealWorkable ? null : (root.source_stage?.slug || '');
if (sourceSlug && sourceSlug === targetSlug) return [];

if (isRealWorkable) {
  const d = root.data || {};
  return [{ json: {
    event_type: root.event_type,
    candidate: {
      id: d.id,
      firstname: d.firstname,
      lastname: d.lastname,
      email: d.email,
      phone_number: d.phone || null,
    },
    job: {
      shortcode: d.job?.shortcode || null,
      title: d.job?.title || null,
      id: d.job?.id || null,
      custom_attributes: d.job?.custom_attributes || null,
    },
    source_stage: { slug: null, name: null },
    target_stage: { slug: targetSlug, name: d.stage || '' },
    moved_by_member_id: null,
  } }];
}
return [{ json: root }];

const p = $json.body || $json;
const c = p.candidate || {};
const j = p.job || {};
const missing = [];
if (!c.id) missing.push('candidate.id');
if (!c.firstname) missing.push('candidate.firstname');
if (!c.email) missing.push('candidate.email');
if (!j.shortcode) missing.push('job.shortcode');
if (missing.length) { throw new Error('MISSING_REQUIRED: ' + missing.join(', ')); }

const BUCKET_TO_ROLE = { admin_va: 'GVA', executive_va: 'EVA', bookkeeper_va: 'BK', inside_sales_agent: 'ISA', product_developer: 'PDEV', operations_manager: 'MGR' };
const ROLE_LABEL = { GVA: 'General Virtual Assistant', EVA: 'Executive Virtual Assistant', BK: 'Bookkeeper Virtual Assistant', ISA: 'Inside Sales Agent', PDEV: 'Product Developer', MGR: 'Operations Manager' };
const ROLE_TIER = { GVA: 1, EVA: 1, BK: 2, ISA: 2, PDEV: 3, MGR: 3 };

const bucket = j.custom_attributes?.question_bucket;
let role_type = bucket ? BUCKET_TO_ROLE[bucket] : null;
if (!role_type) {
  const t = (j.title || '').toLowerCase();
  if (t.includes('bookkeep')) role_type = 'BK';
  else if (t.includes('executive')) role_type = 'EVA';
  else if (t.includes('inside sales')) role_type = 'ISA';
  else if (t.includes('operations manager')) role_type = 'MGR';
  else if (t.includes('developer')) role_type = 'PDEV';
  else role_type = 'GVA';
}

return [{ json: {
  workable_id: c.id,
  first_name: c.firstname,
  email: c.email,
  phone_number: c.phone_number || null,
  job_id: j.id,
  job_shortcode: j.shortcode,
  role_type,
  role_label: j.title || ROLE_LABEL[role_type],
  tier: ROLE_TIER[role_type],
} }];

const upstream = $input.first().json;
const incoming = $('Extract + Validate Context').item.json;
let existing = null;
if (Array.isArray(upstream)) { existing = upstream[0] || null; }
else if (Array.isArray(upstream.data)) { existing = upstream.data[0] || null; }
else if (upstream && typeof upstream === 'object' && (upstream.status || upstream.candidate_id)) {
  existing = upstream;
}
if (existing && existing.status && ['invite_sent', 'scored', 'disqualified'].includes(existing.status)) {
  return [];
}
return [{ json: incoming }];

const crypto = require('crypto');
const session_id = crypto.randomUUID();
const invite_sent_at = new Date().toISOString();
const deadline_iso = new Date(Date.now() + 96 * 3600 * 1000).toISOString();

const base = 'https://sv-ats.vercel.app';
const safeEnc = (s) => encodeURIComponent(String(s)).replace(/\(/g, '%28').replace(/\)/g, '%29');
const recording_link = base + '/?s=' + safeEnc(session_id);

const deadline = new Date(deadline_iso).toLocaleString('en-US', {
  timeZone: 'Asia/Manila',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: 'numeric',
  minute: '2-digit',
  hour12: true,
}) + ' Manila time';

return [{ json: { ...$json, session_id, invite_sent_at, deadline_iso, deadline, recording_link } }];

